class Solution:
    def smallestSubsequence(self, s, k, letter, repetition):
        n = len(s)
        suffix_count = [0] * (n + 1)
        for i in range(n - 1, -1, -1):
            suffix_count[i] = suffix_count[i + 1] + (1 if s[i] == letter else 0)
        stack = []
        need = repetition
        for i, ch in enumerate(s):
            while stack and stack[-1] > ch and len(stack) - 1 + (n - i) >= k:
                top = stack[-1]
                if top == letter:
                    if need >= suffix_count[i]:
                        break
                    need += 1
                stack.pop()
            if len(stack) < k:
                if ch == letter:
                    stack.append(ch)
                    need -= 1
                elif (k - len(stack)) > need:
                    stack.append(ch)
        return ''.join(stack)

