var smallestSubsequence = function(s, k, letter, repetition) {
    const n = s.length;
    const suffixCount = new Array(n + 1).fill(0);
    for (let i = n - 1; i >= 0; i--) {
        suffixCount[i] = suffixCount[i + 1] + (s[i] === letter ? 1 : 0);
    }
    const stack = [];
    let need = repetition;
    for (let i = 0; i < n; i++) {
        const ch = s[i];
        while (stack.length && stack[stack.length - 1] > ch && (stack.length - 1 + (n - i)) >= k) {
            const top = stack[stack.length - 1];
            if (top === letter) {
                if (need >= suffixCount[i]) break;
                need += 1;
            }
            stack.pop();
        }
        if (stack.length < k) {
            if (ch === letter) {
                stack.push(ch);
                need -= 1;
            } else if ((k - stack.length) > need) {
                stack.push(ch);
            }
        }
    }
    return stack.join('');
};
